-- Luke Chapter 15
-- Theme: The Joy of God Over One Sinner Who Repents — Three Parables of the Lost
-- 32 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 15,
  'Luke 15 is justly regarded as the crown of Luke''s Gospel and one of the most theologically profound chapters in the entire NT. The setting is a crisis: tax collectors and sinners are drawing near to Jesus (v.1), and the Pharisees and scribes are murmuring — "This man receiveth sinners, and eateth with them" (v.2). Jesus''s response is three parables, each escalating in emotional intensity and theological depth, each making exactly the same point from a different angle: God actively seeks what is lost, and heaven explodes with joy when the lost is found.' ||
  'The parable of the lost sheep (vv.3-7) features a shepherd who leaves ninety-nine sheep to search for one. The parable of the lost coin (vv.8-10) features a woman who lights a lamp and sweeps her entire house to find one silver coin. Both parables end with the same refrain: rejoicing with friends and neighbours, and "I say unto you, there is joy in the presence of the angels of God over one sinner that repenteth." Both are deliberately short; both are designed to shame the Pharisees who murmur rather than rejoice at sinners'' recovery.' ||
  'The parable of the prodigal son (vv.11-32) is the longest and most complex of the three. It is properly the parable of two sons and a father. The younger son demands his inheritance, squanders it in a far country, "comes to himself," returns, and is met by a running father whose embrace and celebration are extravagant beyond all social expectation. The language of the father''s welcome (robe, ring, shoes, fatted calf) is the language of restoration to full sonship. At the center of the parable (v.24) stands the great resurrection formula: "this my son was dead, and is alive again; he was lost, and is found."' ||
  'The parable''s second half (vv.25-32) introduces the elder son — a portrait of the murmuring Pharisee — who refuses to enter the celebration. His complaint reveals a spirit of legal merit, resentment at grace, and failure to understand the father''s heart. The father goes out to him as well, pleading gently. The parable ends without resolution — the elder son''s response is left open — because Luke''s reader (the Pharisee) must decide. All three parables answer the Pharisees'' murmur not with argument but with a portrayal of God''s own joy over the found.',
  'The Joy of God Over One Sinner Who Repents — Three Parables of the Lost',
  'εὑρίσκω (heuriskō)',
  'heuriskō means to find, to discover, to come upon. In Luke 15 it is the climactic verb of all three parables: the shepherd "findeth" (heurōn) the lost sheep (v.5); the woman "findeth" (heurousa) the lost coin (v.9); the father declares "he was lost, and is found" (heurethē) twice (vv.24,32). The finding in each case is not accidental but the result of active, intentional, costly searching. The verb drives the theology of the chapter: God does not wait for the lost to find him but goes seeking until recovery is accomplished. The joy of finding (v.6,9,24,32) is the joy of God himself.',
  '["The Lost Sheep: One Out of Ninety-Nine (vv.1-7)","The Lost Coin: One Out of Ten (vv.8-10)","The Prodigal Son: The Younger Brother''s Journey and Return (vv.11-24)","The Elder Brother: Grace Refused and the Father''s Plea (vv.25-32)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Then drew near unto him all the publicans and sinners for to hear him.', 'Ἦσαν δὲ αὐτῷ ἐγγίζοντες πάντες οἱ τελῶναι καὶ οἱ ἁμαρτωλοὶ ἀκούειν αὐτοῦ.', 'Ēsan de autō engizOntes pantes hoi telōnai kai hoi hamartōloi akouein autou.', '"Drew near" (engizOntes — were drawing near, approaching, an imperfect indicating continuous movement) — the tax collectors and sinners are not merely present but actively pressing toward Jesus to hear. Their hunger for his words is contrasted with the Pharisees'' hostility. "All" (pantes) — the comprehensiveness of the attraction: people regarded as the most disqualified found Jesus most magnetic. This social reality becomes the occasion for all three parables.', NULL),
  (2, 'And the Pharisees and scribes murmured, saying, This man receiveth sinners, and eateth with them.', 'καὶ διεγόγγυζον οἵ τε Φαρισαῖοι καὶ οἱ γραμματεῖς λέγοντες ὅτι Οὗτος ἁμαρτωλοὺς προσδέχεται καὶ συνεσθίει αὐτοῖς.', 'kai diegogguzon hoi te Pharisaioi kai hoi grammateis legontes hoti Houtos hamartōlous prosdechetai kai sunesthiei autois.', '"Murmured" (diegogguzon — kept grumbling, the imperfect describing ongoing complaint; a word that echoes Israel''s wilderness murmuring against God, Num 11:1). "Receiveth" (prosdechetai — welcomes, accepts, receives as a guest) and "eateth with them" (sunesthiei — eats together with) — table fellowship was an intimate social act signaling acceptance and equality. The Pharisees'' complaint is that Jesus not only tolerates sinners but actively welcomes them and eats with them. This is the theological crisis that the three parables address.', NULL),
  (3, 'And he spake this parable unto them, saying,', 'εἶπεν δὲ πρὸς αὐτοὺς τὴν παραβολὴν ταύτην λέγων,', 'eipen de pros autous tēn parabolēn tautēn legōn,', 'The singular "parable" (parabolēn — singular, yet what follows are three parables) suggests that all three stories are one unified response to the same murmur. Luke frames them as a single extended reply. Jesus addresses his answer not defensively ("I have the right to eat with sinners") but offensively ("let me show you the heart of God"). The parables do not justify Jesus''s behavior; they portray God''s joy, which the Pharisees do not share.', NULL),
  (4, 'What man of you, having an hundred sheep, if he lose one of them, doth not leave the ninety and nine in the wilderness, and go after that which is lost, until he find it?', 'Τίς ἄνθρωπος ἐξ ὑμῶν ἔχων ἑκατὸν πρόβατα καὶ ἀπολέσας ἐξ αὐτῶν ἓν οὐ καταλείπει τὰ ἐνενήκοντα ἐννέα ἐν τῇ ἐρήμῳ καὶ πορεύεται ἐπὶ τὸ ἀπολωλὸς ἕως εὕρῃ αὐτό;', 'Tis anthrōpos ex humōn echōn hekaton probata kai apolEsas ex autōn hen ou kataleipei ta enenēkonta ennea en tē erēmō kai poreuetai epi to apolōlos heōs heurē auto?', 'The rhetorical question (Tis anthrōpos ex humōn — which man among you) invites the Pharisees into the shepherd''s perspective — they are expected to agree that a shepherd would leave the ninety-nine to search for the one. "Until he find it" (heōs heurē auto — until the moment he finds it) — the search is persistent and uninterrupted. The shepherd does not give up, adjust the odds, or settle for 99%. The one lost sheep has the full, undivided attention of the shepherd until found.', NULL),
  (5, 'And when he hath found it, he layeth it on his shoulders, rejoicing.', 'καὶ εὑρὼν ἐπιτίθησιν ἐπὶ τοὺς ὤμους αὐτοῦ χαίρων·', 'kai heurōn epitithēsin epi tous ōmous autou chairōn;', '"Layeth it on his shoulders" (epitithēsin epi tous ōmous autou — places it upon his own shoulders) — not driving it back but carrying it. A lost, exhausted sheep cannot walk home; the shepherd bears it. This is a physical image of redemption: the shepherd does not merely find and point the way but lifts the straying creature onto himself for the journey home. "Rejoicing" (chairōn — present participle: actively rejoicing, while carrying) — the joy begins not at arrival but at the moment of finding.', NULL),
  (6, 'And when he cometh home, he calleth together his friends and neighbours, saying unto them, Rejoice with me; for I have found my sheep which was lost.', 'καὶ ἐλθὼν εἰς τὸν οἶκον συγκαλεῖ τοὺς φίλους καὶ τοὺς γείτονας, λέγων αὐτοῖς, Συγχάρητέ μοι, ὅτι εὗρον τὸ πρόβατόν μου τὸ ἀπολωλός.', 'kai elthōn eis ton oikon sungkalei tous philous kai tous geitonas, legōn autois, Sungcharēte moi, hoti heuron to probaton mou to apolōlos.', '"Calleth together his friends and neighbours" (sungkalei — summons, calls together) — the joy is too large to contain alone; it demands community. "Rejoice with me" (sungcharēte moi — rejoice together with me) — share in my joy. "My sheep which was lost" (to probaton mou to apolōlos — my sheep, the one that was lost, the perfect participle indicating the state of lostness that has now been reversed) — the possessive "my" reveals the shepherd''s personal attachment. It was not just a sheep but his sheep.', NULL),
  (7, 'I say unto you, that likewise joy shall be in heaven over one sinner that repenteth, more than over ninety and nine just persons, which need no repentance.', 'λέγω ὑμῖν ὅτι οὕτως χαρὰ ἐν τῷ οὐρανῷ ἔσται ἐπὶ ἑνὶ ἁμαρτωλῷ μετανοοῦντι ἢ ἐπὶ ἐνενήκοντα ἐννέα δικαίοις οἵτινες οὐ χρείαν ἔχουσιν μετανοίας.', 'legō humin hoti houtōs chara en tō ouranō estai epi heni hamartōlō metanounti ē epi enenēkonta ennea dikaiois hoitines ou chreian echousin metanoias.', '"Joy in heaven" (chara en tō ouranō) — heaven''s joy over one repenting sinner exceeds its joy over ninety-nine just persons who need no repentance. The "ninety-nine just persons who need no repentance" is ironic: the Pharisees considered themselves in this category, but in fact no human being qualifies. The statement both honors genuine righteousness and exposes the comparative indifference that fails to rejoice at a sinner''s return — the very emotion the Pharisees displayed in v.2.', NULL),
  (8, 'Either what woman having ten pieces of silver, if she lose one piece, doth not light a candle, and sweep the house, and seek diligently till she find it?', 'Ἢ τίς γυνὴ δραχμὰς ἔχουσα δέκα, ἐὰν ἀπολέσῃ δραχμὴν μίαν, οὐχὶ ἅπτει λύχνον καὶ σαροῖ τὴν οἰκίαν καὶ ζητεῖ ἐπιμελῶς ἕως οὗ εὕρῃ;', 'Ē tis gunē drachmas echousa deka, ean apolEsē drachmēn mian, ouchi haptei luchnon kai saroi tēn oikian kai zētei epimelōs heōs hou heurē?', 'The second parable shifts to a woman — Luke''s characteristic pairing of male (shepherd) and female (woman) examples (cf. 13:18-21). A drachma was roughly equivalent to a denarius — a day''s wage. Ten drachmas may have been her entire savings or possibly her dowry coins worn as a headdress. "Light a candle" (haptei luchnon — lights a lamp), "sweep the house" (saroi — sweeps carefully), "seek diligently" (zētei epimelōs — searches with care and attention) — three actions escalating in effort. The enclosed Palestinian house required a lamp to find a small coin.', NULL),
  (9, 'And when she hath found it, she calleth her friends and her neighbours together, saying, Rejoice with me; for I have found the piece which I had lost.', 'καὶ εὑροῦσα συγκαλεῖ τὰς φίλας καὶ γείτονας λέγουσα, Συγχάρητέ μοι, ὅτι εὗρον τὴν δραχμὴν ἣν ἀπώλεσα.', 'kai heurousa sungkalei tas philas kai geitonas legousa, Sungcharēte moi, hoti heuron tēn drachmēn hēn apōlesa.', 'The woman''s response mirrors the shepherd''s exactly: she summons her female friends and neighbors (philas — feminine form) to share her joy. "Rejoice with me" (sungcharēte moi) — the same call. "Which I had lost" (hēn apōlesa — which I lost, aorist: a specific past event) — the personal past loss and the present finding together constitute the reason for communal joy. The community''s shared joy reflects heaven''s; those who refuse to rejoice with the woman are refusing to share in God''s own emotion.', NULL),
  (10, 'Likewise, I say unto you, there is joy in the presence of the angels of God over one sinner that repenteth.', 'οὕτως λέγω ὑμῖν, χαρὰ γίνεται ἐνώπιον τῶν ἀγγέλων τοῦ Θεοῦ ἐπὶ ἑνὶ ἁμαρτωλῷ μετανοοῦντι.', 'houtōs legō humin, chara ginetai enōpion tōn angelōn tou Theou epi heni hamartōlō metanounti.', '"In the presence of the angels" (enōpion tōn angelōn tou Theou) — the joy is before, in the presence of, the angelic court. Some commentators suggest the joy belongs to God himself ("before the angels" meaning in God''s own throne room); others that the angels themselves rejoice. Either way, a single sinner''s repentance reverberates through the entire heavenly realm. The Pharisees who murmur at sinners'' return are not in sympathy with heaven''s own emotion — they stand against the heart of God.', NULL),
  (11, 'And he said, A certain man had two sons:', 'Εἶπεν δέ, Ἄνθρωπός τις εἶχεν δύο υἱούς.', 'Eipen de, Anthrōpos tis eichen duo huious.', 'The third and longest parable begins with stark economy: "a certain man had two sons" — eight words in Greek, three in English. No names, no location, no backstory. The focus is entirely on relationships and responses. The "two sons" structure is crucial: the parable is not only about the younger son''s redemption but about the elder son''s resentment. Both sons have a broken relationship with the father; one is restored, the other''s restoration remains open. The father is the center of both stories.', NULL),
  (12, 'And the younger of them said to his father, Father, give me the portion of goods that falleth to me. And he divided unto them his living.', 'καὶ εἶπεν ὁ νεώτερος αὐτῶν τῷ πατρί, Πάτερ, δός μοι τὸ ἐπιβάλλον μέρος τῆς οὐσίας. ὁ δὲ διεῖλεν αὐτοῖς τὸν βίον.', 'kai eipen ho neōteros autōn tō patri, Pater, dos moi to epiballon meros tēs ousias. ho de dieilen autois ton bion.', 'In Jewish law, the younger son could receive his share (one third) only at the father''s death or by special request; to demand it while the father lives was equivalent to wishing him dead — a profound social dishonor. "Give me" (dos moi — hand over to me, imperative with no courtesy) reveals the son''s posture. The father''s response — "divided unto them his living" (dieilen autois ton bion — divided between them his means of life) — is neither vindictive nor weak; it is the extraordinary love that allows freedom even at great cost.', NULL),
  (13, 'And not many days after the younger son gathered all together, and took his journey into a far country, and there wasted his substance with riotous living.', 'καὶ μετ'' οὐ πολλὰς ἡμέρας συναγαγὼν ἅπαντα ὁ νεώτερος υἱὸς ἀπεδήμησεν εἰς χώραν μακράν, καὶ ἐκεῖ διεσκόρπισεν τὴν οὐσίαν αὐτοῦ ζῶν ἀσώτως.', 'kai met'' ou pollas hēmeras sunagagōn hapanta ho neōteros huios apedēmesen eis chōran makran, kai ekei dieskorpisen tēn ousian autou zōn asōtōs.', '"Not many days after" — no gradual drift but an immediate departure. "Gathered all together" (sunagagōn hapanta — collecting everything, liquidating all assets) — he converts the estate portion to portable wealth. "Far country" (chōran makran — a distant land) — maximum distance from the father. "Wasted his substance" (dieskorpisen tēn ousian autou — scattered, squandered his property, the same word used for scattering seed randomly) "with riotous living" (zōn asōtōs — living without saving, dissolute, profligate).', NULL),
  (14, 'And when he had spent all, there arose a mighty famine in that land; and he began to be in want.', 'δαπανήσαντος δὲ αὐτοῦ πάντα ἐγένετο λιμὸς ἰσχυρὸς κατὰ τὴν χώραν ἐκείνην, καὶ αὐτὸς ἤρξατο ὑστερεῖσθαι.', 'dapanēsantos de autou panta egeneto limos ischuros kata tēn chōran ekeinēn, kai autos ērxato hustereisthai.', '"When he had spent all" (dapanēsantos de autou panta — when he had used up everything, aorist genitive absolute) — complete depletion and the timing of the famine are not coincidental in the narrative; they are compounded disciplines. "Mighty famine" (limos ischuros — a severe, powerful famine) — he has no resources to weather the crisis. "Began to be in want" (ērxato hustereisthai — started to lack, to fall behind, to be in deficit) — the movement from profligacy to poverty is rapid and complete.', NULL),
  (15, 'And he went and joined himself to a citizen of that country; and he sent him into his fields to feed swine.', 'καὶ πορευθεὶς ἐκολλήθη ἑνὶ τῶν πολιτῶν τῆς χώρας ἐκείνης, καὶ ἔπεμψεν αὐτὸν εἰς τοὺς ἀγροὺς αὐτοῦ βόσκειν χοίρους.', 'kai poreutheis ekollēthē heni tōn politōn tēs chōras ekeinēs, kai epempsen auton eis tous agrous autou boskein choirous.', '"Joined himself" (ekollēthē — cleaved to, attached himself, the word for a close bond, as of marriage) — the desperation of attachment to any available help. "Feed swine" (boskein choirous) — for a Jewish young man, the lowest imaginable employment: tending ceremonially unclean animals (Lev 11:7). He is not only in a far country but at the furthest possible distance from Jewish identity, Torah, and home. The employment is a measure of his complete degradation.', NULL),
  (16, 'And he would fain have filled his belly with the husks that the swine did eat: and no man gave unto him.', 'καὶ ἐπεθύμει γεμίσαι τὴν κοιλίαν αὐτοῦ ἀπὸ τῶν κερατίων ὧν ἤσθιον οἱ χοῖροι, καὶ οὐδεὶς ἐδίδου αὐτῷ.', 'kai epethumei gemisai tēn koilian autou apo tōn keratōn hōn ēsthion hoi choiroi, kai oudeis edidou autō.', '"Would fain have filled his belly" (epethumei gemisai — was longing, craving to fill his stomach, the imperfect of intense unfulfilled desire) "with the husks" (keratiōn — carob pods, the food of pigs and the poorest people). "No man gave unto him" (oudeis edidou autō — no one was giving to him) — complete abandonment by every human source. The far country offers nothing. He who left his father''s house with wealth is now beneath the pigs he tends. The bottom has been reached.', NULL),
  (17, 'And when he came to himself, he said, How many hired servants of my father''s have bread enough and to spare, and I perish with hunger!', 'εἰς ἑαυτὸν δὲ ἐλθὼν εἶπεν, Πόσοι μίσθιοι τοῦ πατρός μου περισσεύουσιν ἄρτων, ἐγὼ δὲ λιμῷ ὧδε ἀπόλλυμαι.', 'eis heauton de elthōn eipen, Posoi misthioi tou patros mou perisseuousin artōn, egō de limō hōde apollumai.', '"Came to himself" (eis heauton de elthōn — having come to himself, returned to his senses, a Greek idiom for recovery of reason after delusion or stupor) — one of the most psychologically precise phrases in the NT. Sin is a form of self-alienation; repentance is the recovery of one''s true self. "How many hired servants of my father''s" — even the lowest-paid workers in his father''s household have more than enough (perisseuousin — have abundance). The comparison strikes his conscience: he has exchanged a servant''s abundance for a pig-feeder''s starvation.', NULL),
  (18, 'I will arise and go to my father, and will say unto him, Father, I have sinned against heaven, and before thee,', 'ἀναστὰς πορεύσομαι πρὸς τὸν πατέρα μου καὶ ἐρῶ αὐτῷ, Πάτερ, ἥμαρτον εἰς τὸν οὐρανὸν καὶ ἐνώπιόν σου,', 'anastas poreusomai pros ton patera mou kai erō autō, Pater, hēmarton eis ton ouranon kai enōpion sou,', '"I will arise" (anastas — rising up, a word also used for resurrection) and "go to my father" — the decision to return. "Father, I have sinned" (Pater, hēmarton — I sinned, aorist: a completed act with ongoing consequences) "against heaven" (eis ton ouranon — toward heaven, against God) "and before thee" (enōpion sou — in your sight). The confession has two dimensions: vertical (against God) and horizontal (against the father). True repentance acknowledges both, and the son rehearses his speech — a sign of genuine forethought, not mere impulse.', NULL),
  (19, 'And am no more worthy to be called thy son: make me as one of thy hired servants.', 'οὐκέτι εἰμὶ ἄξιος κληθῆναι υἱός σου· ποίησόν με ὡς ἕνα τῶν μισθίων σου.', 'oukEti eimi axios klēthēnai huios sou; poiEson me hōs hena tōn misthiōn sou.', '"No more worthy to be called thy son" (oukEti eimi axios klēthēnai huios sou — I am no longer worthy to be named your son) — a realistic self-assessment without false modesty. Sonship has been forfeited by his actions. "Make me as one of thy hired servants" (misthiōn — day laborers, who were employed temporarily and had no household status) — he will not ask to be reinstated as a son but only for servant employment. This is the planned content of his confession; what the father actually does will far exceed his request.', NULL),
  (20, 'And he arose, and came to his father. But when he was yet a great way off, his father saw him, and had compassion, and ran, and fell on his neck, and kissed him.', 'καὶ ἀναστὰς ἦλθεν πρὸς τὸν πατέρα ἑαυτοῦ. ἔτι δὲ αὐτοῦ μακρὰν ἀπέχοντος εἶδεν αὐτὸν ὁ πατὴρ αὐτοῦ καὶ ἐσπλαγχνίσθη, καὶ δραμὼν ἐπέπεσεν ἐπὶ τὸν τράχηλον αὐτοῦ καὶ κατεφίλησεν αὐτόν.', 'kai anastas ēlthen pros ton patera heautou. eti de autou makran apechontos eiden auton ho patēr autou kai esplanchnisthē, kai dramōn epepesen epi ton trachēlon autou kai katephilēsen auton.', '"Yet a great way off" (makran apechontos — while still far distant) — the father was watching. "Saw him" — the father recognizes him at a distance, suggesting he had been watching the road. "Had compassion" (esplanchnisthē — was moved in the bowels, deep visceral compassion). "Ran" (dramōn — running) — an undignified act for a Middle Eastern patriarch, scandalous in that culture. He runs to intercept the shame before it fully arrives. "Fell on his neck" and "kissed him" (katephilēsen — kissed tenderly, repeatedly) — the embrace prevents the son from completing his prostration.', NULL),
  (21, 'And the son said unto him, Father, I have sinned against heaven, and in thy sight, and am no more worthy to be called thy son.', 'εἶπεν δὲ ὁ υἱός, Πάτερ, ἥμαρτον εἰς τὸν οὐρανὸν καὶ ἐνώπιόν σου, οὐκέτι εἰμὶ ἄξιος κληθῆναι υἱός σου.', 'eipen de ho huios, Pater, hēmarton eis ton ouranon kai enōpion sou, oukEti eimi axios klēthēnai huios sou.', 'The son delivers his rehearsed confession — but only the first part. He confesses sin against heaven and the father, and declares himself unworthy of sonship. He never gets to say "make me as one of thy hired servants" (v.19) because the father interrupts with commands of restoration. The confession is genuine and complete; the father does not need to hear the servant-request because he has already decided to restore sonship. The father''s response exceeds everything the son planned to ask.', NULL),
  (22, 'But the father said to his servants, Bring forth the best robe, and put it on him; and put a ring on his hand, and shoes on his feet:', 'εἶπεν δὲ ὁ πατὴρ πρὸς τοὺς δούλους αὐτοῦ, Ταχὺ ἐξενέγκατε στολὴν τὴν πρώτην καὶ ἐνδύσατε αὐτόν, καὶ δότε δακτύλιον εἰς τὴν χεῖρα αὐτοῦ καὶ ὑποδήματα εἰς τοὺς πόδας,', 'eipen de ho patēr pros tous doulous autou, Tachu exenegkate stolēn tēn prōtēn kai endusate auton, kai dote daktulion eis tēn cheira autou kai hupodēmata eis tous podas,', '"The best robe" (stolēn tēn prōtēn — the first robe, the finest robe, place of honor) — placed on the ragged wanderer immediately. "A ring" (daktulion — a signet ring, symbol of authority and family identity, perhaps the family seal). "Shoes on his feet" — slaves went barefoot; free men wore sandals. The three gifts together restore full sonship: dignity (robe), authority (ring), freedom (shoes). There is no probationary period, no testing of sincerity — the restoration is immediate, complete, and public.', NULL),
  (23, 'And bring hither the fatted calf, and kill it; and let us eat, and be merry:', 'καὶ φέρετε τὸν μόσχον τὸν σιτευτόν, θύσατε, καὶ φαγόντες εὐφρανθῶμεν,', 'kai pherete ton moschon ton siteuton, thusate, kai phagontes euphrantōmen,', '"The fatted calf" (ton moschon ton siteuton — the fattened young bull, grain-fed and reserved for a special occasion) — the most expensive possible celebration, enough meat for the entire village. A fatted calf is not slaughtered for a small family dinner but for a communal feast. The father throws the village a party. "Let us eat, and be merry" (phagontes euphrantōmen — having eaten let us rejoice) — the language of genuine, exuberant celebration, not solemn ceremony.', NULL),
  (24, 'For this my son was dead, and is alive again; he was lost, and is found. And they began to be merry.', 'ὅτι οὗτος ὁ υἱός μου νεκρὸς ἦν καὶ ἀνέζησεν, καὶ ἀπολωλὼς ἦν καὶ εὑρέθη. καὶ ἤρξαντο εὐφραίνεσθαι.', 'hoti houtos ho huios mou nekros ēn kai anEzēsen, kai apolōlos ēn kai heurethē. kai ērxanto euphrainesth​ai.', '"This my son" (houtos ho huios mou) — "my son" — the father never stopped calling him son even when he was in the far country. "Was dead, and is alive again" (nekros ēn kai anEzEsen — dead and came to life again) — the resurrection language is explicit: the prodigal''s return is a kind of resurrection, a coming back from the dead. "Was lost, and is found" (apolōlos ēn kai heurethē — the echo of the lost sheep and coin). The two pairs of contrasts — dead/alive, lost/found — are the theological key of the entire chapter and of the gospel of grace.', NULL),
  (25, 'Now his elder son was in the field: and as he came and drew nigh to the house, he heard musick and dancing.', 'Ἦν δὲ ὁ υἱὸς αὐτοῦ ὁ πρεσβύτερος ἐν ἀγρῷ· καὶ ὡς ἐρχόμενος ἤγγισεν τῇ οἰκίᾳ, ἤκουσεν συμφωνίας καὶ χορῶν,', 'Ēn de ho huios autou ho presbUteros en agrō; kai hōs erchomenos ēngisen tē oikia, ēkousen sumphōnias kai chorōn,', 'The narrative''s second half pivots to the elder son — in the field, working. He is the model of outward faithfulness: in the field, not the far country. As he approaches home (ēngisen — drew near, the same verb as the sinners in v.1 drawing near to Jesus), he hears music and dancing (sumphōnias kai chorōn — symphony and circle dances). He does not know the reason; he must ask. His distance from his father''s joy, despite physical proximity, is the parable''s second tragedy.', NULL),
  (26, 'And he called one of the servants, and asked what these things meant.', 'καὶ προσκαλεσάμενος ἕνα τῶν παίδων ἐπυνθάνετο τί ἂν εἴη ταῦτα.', 'kai proskalesamenos hena tōn paidōn epunthaneto ti an eiē tauta.', '"Called one of the servants" (proskalesamenos hena tōn paidōn) — he does not go in and find out himself but sends for information. He maintains distance even before he knows the reason. "Asked what these things meant" (epunthaneto ti an eiē tauta — was inquiring what these things might be) — the use of the optative mood (eiē — might be) in the indirect question suggests polite formality; he is controlling his approach. His subsequent refusal to enter (v.28) shows that the distance was emotional before it was physical.', NULL),
  (27, 'And he said unto him, Thy brother is come; and thy father hath killed the fatted calf, because he hath received him safe and sound.', 'ὁ δὲ εἶπεν αὐτῷ ὅτι Ὁ ἀδελφός σου ἥκει, καὶ ἔθυσεν ὁ πατήρ σου τὸν μόσχον τὸν σιτευτόν, ὅτι ὑγιαίνοντα αὐτὸν ἀπέλαβεν.', 'ho de eipen autō hoti Ho adelphos sou hēkei, kai ethusen ho patēr sou ton moschon ton siteuton, hoti hugiainonta auton apElaben.', '"Thy brother is come" (Ho adelphos sou hēkei — your brother has arrived) — the servant identifies the returned man as "thy brother," emphasizing the family relationship. "Safe and sound" (hugiainonta — in good health, whole, the same word family as "save"). The elder son''s reaction will show that he does not currently regard the younger as a brother — he will refer to him as "this thy son" (v.30), refusing the fraternal relationship. The servant''s simple report contains the seed of the elder son''s crisis.', NULL),
  (28, 'And he was angry, and would not go in: therefore came his father out, and intreated him.', 'ὠργίσθη δὲ καὶ οὐκ ἤθελεν εἰσελθεῖν. ὁ δὲ πατὴρ αὐτοῦ ἐξελθὼν παρεκάλει αὐτόν.', 'ōrgisthē de kai ouk ēthelen eiselthein. ho de patēr autou exelthōn parekalei auton.', '"He was angry" (ōrgisthē — he became enraged, aorist) "and would not go in" (ouk ēthelen eiselthein — was not willing to enter) — a deliberate, willful refusal. The elder son''s anger is the Pharisees'' murmur translated into the parable. As the Pharisees refused to rejoice at sinners drawing near (v.2), the elder son refuses to enter the celebration of his brother''s return. "His father came out" (exelthōn) — again the father takes the initiative; he went out to the prodigal; he goes out to the elder son. Grace pursues both.', NULL),
  (29, 'And he answering said to his father, Lo, these many years do I serve thee, neither transgressed I at any time thy commandment: and yet thou never gavest me a kid, that I might make merry with my friends:', 'ὁ δὲ ἀποκριθεὶς εἶπεν τῷ πατρὶ αὐτοῦ, Ἰδοὺ τοσαῦτα ἔτη δουλεύω σοι καὶ οὐδέποτε ἐντολήν σου παρῆλθον, καὶ ἐμοὶ οὐδέποτε ἔδωκας ἔριφον ἵνα μετὰ τῶν φίλων μου εὐφρανθῶ·', 'ho de apokritheis eipen tō patri autou, Idou tosanta etē douleuō soi kai oudepote entolēn sou parēlthon, kai emoi oudepote edōkas eRiphon hina meta tōn philōn mou euphrantōmen;', '"Lo, these many years do I serve thee" (douleuō soi — I serve/slave for you; the slave-word, not the son-word!) — a devastating self-revelation: the elder son understands his relationship to the father as servitude, not sonship. He has been in the house all along but as a servant earning wages, not as a son living in love. "Never gavest me a kid" — even a small animal for his friends, not the best calf. The resentment of legal religion: meticulous obedience but no experience of the father''s joy.', NULL),
  (30, 'But as soon as this thy son was come, which hath devoured thy living with harlots, thou hast killed for him the fatted calf.', 'ὅτε δὲ ὁ υἱός σου οὗτος ὁ καταφαγὼν σου τὸν βίον μετὰ πορνῶν ἦλθεν, ἔθυσας αὐτῷ τὸν μόσχον τὸν σιτευτόν.', 'hote de ho huios sou houtos ho kataphagōn sou ton bion meta pornōn ēlthen, ethuSas autō ton moschon ton siteuton.', '"This thy son" (ho huios sou houtos — this son of yours) — the elder son cannot say "my brother"; he distances himself from both the prodigal and the relationship. "Which hath devoured thy living with harlots" (meta pornōn — with prostitutes) — information the father has not mentioned; the elder son assumes the worst. The word pornōn will resonate with the Pharisees who knew Luke''s readers were aware of the prodigal''s "riotous living" (v.13). The elder son''s contempt for grace reveals his fundamental misunderstanding of the father''s heart.', NULL),
  (31, 'And he said unto him, Son, thou art ever with me, and all that I have is thine.', 'ὁ δὲ εἶπεν αὐτῷ, Τέκνον, σὺ πάντοτε μετ'' ἐμοῦ εἶ, καὶ πάντα τὰ ἐμὰ σά ἐστιν·', 'ho de eipen autō, Teknon, su pantote met'' emou ei, kai panta ta ema sa estin;', '"Son" (Teknon — child, a tender, intimate form of address) — the father does not rebuke but reassures. "Thou art ever with me" (pantote met'' emou ei — you are always with me) — this is precisely the blessing the elder son has not recognized: constant access to the father''s presence. "All that I have is thine" (panta ta ema sa estin — all my things are yours) — the elder son already possesses everything; he has not needed to ask because it was always his. His poverty was not material but experiential — he did not know what he had.', NULL),
  (32, 'It was meet that we should make merry, and be glad: for this thy brother was dead, and is alive again; and was lost, and is found.', 'εὐφρανθῆναι δὲ καὶ χαρῆναι ἔδει, ὅτι ὁ ἀδελφός σου οὗτος νεκρὸς ἦν καὶ ἀνέζησεν, καὶ ἀπολωλὼς καὶ εὑρέθη.', 'euphranthenai de kai charēnai edei, hoti ho adelphos sou houtos nekros ēn kai anEzēsen, kai apolōlos kai heurethē.', '"It was meet" (edei — it was necessary, it was fitting, it had to be) — the celebration is not arbitrary or excessive; it is morally and theologically necessary given the facts. The father now says "this thy brother" (ho adelphos sou houtos) — deliberately using the fraternal language the elder son refused. The parable ends with the same resurrection formula as v.24: "was dead, and is alive again; was lost, and is found." The open ending — we never learn if the elder son enters — is the literary genius of the parable: the Pharisee must decide how the story ends for himself.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 15;
